const canvas = document.getElementById('gameCanvas');
const canvasContext = canvas.getContext('2d');

const BOARD_SIZE = 800;
const SQUARE_DIMENSION = 100;

let gameState = {
    board: [],
    currentPlayerColor: 'white',
    turn: 'human',
    selectedSource: null, // { row: 7, col: 1 } for example
    possibleMoves: []     // [{ row: 6, col: 1 }, ...]
};

/**
 * Initializes the game state: sets up the standard starting chessboard positions.
 */
function initializeGame() {
    // Initialize an 8x8 board array
    gameState.board = Array(8).fill(0).map(() => Array(8).fill(null));

    // Piece setup standard notation (Row 0 is Black's back rank, Row 7 is White's back rank)

    // Black Pieces (Row 0 and 1)
    // Row 0: R N B Q K B N R
    gameState.board[0] = ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R'];
    // Row 1: P P P P P P P P
    gameState.board[1] = ['P', 'P', 'P', 'P', 'P', 'P', 'P', 'P'];

    // Empty rows 2 through 5
    for (let i = 2; i <= 5; i++) {
        gameState.board[i].fill(null);
    }

    // White Pieces (Row 6 and 7)
    // Row 7: R N B Q K B N R
    gameState.board[7] = ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R'];
    // Row 6: P P P P P P P P
    gameState.board[6] = ['P', 'P', 'P', 'P', 'P', 'P', 'P', 'P'];

    // Starting state
    gameState.currentPlayerColor = 'white';
    gameState.turn = 'human';
    gameState.selectedSource = null;
    gameState.possibleMoves = [];

    console.log("Game Initialized.");
    renderBoard();
}

/**
 * Draws a single piece symbol onto the canvas at the specified coordinates.
 * @param {string} pieceSymbol - The piece type ('R', 'P', etc.).
 * @param {number} row - The row index (0-7).
 * @param {number} col - The column index (0-7).
 * @param {string} color - 'white' or 'black' to determine the drawn color.
 */
function drawPiece(pieceSymbol, row, col, color) {
    const centerX = col * SQUARE_DIMENSION + SQUARE_DIMENSION / 2;
    const centerY = row * SQUARE_DIMENSION + SQUARE_DIMENSION / 2;
    const drawSize = SQUARE_DIMENSION * 0.8;

    canvasContext.fillStyle = (color === 'white') ? '#FFFFFF' : '#000000';
    canvasContext.strokeStyle = '#333333';
    canvasContext.lineWidth = 2;

    canvasContext.beginPath();
    canvasContext.arc(centerX, centerY, drawSize / 2, 0, Math.PI * 2);
    canvasContext.fill();
    canvasContext.stroke();

    canvasContext.fillStyle = (color === 'white') ? '#000000' : '#FFFFFF';
    canvasContext.font = `${drawSize * 0.5}px Arial`;
    canvasContext.textAlign = 'center';
    canvasContext.textBaseline = 'middle';
    canvasContext.fillText(pieceSymbol, centerX, centerY);
}

/**
 * Determines the color of the piece at a given board location.
 * NOTE: This function is highly heuristic given the manual initialization structure.
 * We improve it by checking if the piece is placed on the historically black or white side.
 * @param {string} pieceCode - The code from the game state board (e.g., 'P', 'R').
 * @param {number} row - The row index.
 * @param {number} col - The column index.
 * @returns {string | null} 'white' or 'black', or null if empty.
 */
function getPieceColor(pieceCode, row, col) {
    if (!pieceCode) return null;

    // White pieces occupy rows 6 and 7 (higher indices in array)
    if (row >= 6) {
        // Check if it matches standard white piece placement
        if(['P', 'R', 'N', 'B', 'Q', 'K'].includes(pieceCode)) {
            return 'white';
        }
    }
    // Black pieces occupy rows 0 and 1 (lower indices in array)
    if (row <= 1) {
        // Check if it matches standard black piece placement
         if(['P', 'R', 'N', 'B', 'Q', 'K'].includes(pieceCode)) {
            return 'black';
        }
    }

    // For pieces manually placed in the middle (if allowed later), this is the fallback that might fail.
    // For the current setup, this should capture everything correctly.
    return null;
}

/**
 * Clears the entire canvas and redraws the board state based on gameState.board.
 */
function renderBoard() {
    // 1. Clear the canvas
    canvasContext.clearRect(0, 0, BOARD_SIZE, BOARD_SIZE);

    // 2. Draw background/squares
    for (let row = 0; row < 8; row++) {
        for (let col = 0; col < 8; col++) {
            const x = col * SQUARE_DIMENSION;
            const y = row * SQUARE_DIMENSION;

            let highlight = false;

            // Check for highlights
            let highlightColor = null;
            if (gameState.selectedSource && gameState.selectedSource.row === row && gameState.selectedSource.col === col) {
                highlightColor = 'rgba(255, 255, 0, 0.5)'; // Selected
                highlight = true;
            } else if (gameState.possibleMoves.some(move => move.row === row && move.col === col)) {
                highlightColor = 'rgba(0, 200, 0, 0.3)'; // Possible move destination
                highlight = true;
            } 

            // Draw the square
            canvasContext.save();
            if (highlight) {
                canvasContext.fillStyle = highlightColor;
                canvasContext.fillRect(x, y, SQUARE_DIMENSION, SQUARE_DIMENSION);
            } else {
                // Standard square color alternation (Assuming A1 is black, which corresponds to (0,0) index)
                // Check (row + col) parity. For standard board visualization, A1 (0,0) parity determines color.
                const color = (row + col) % 2 === 0 ? '#D18B47' : '#FFCE9E';
                canvasContext.fillStyle = color;
                canvasContext.fillRect(x, y, SQUARE_DIMENSION, SQUARE_DIMENSION);
            }
            canvasContext.restore();
        }
    }

    // 3. Draw Pieces
    for (let row = 0; row < 8; row++) {
        for (let col = 0; col < 8; col++) {
            const pieceCode = gameState.board[row][col];
            if (pieceCode) {
                let pieceColor = getPieceColor(pieceCode, row, col); 
                if (pieceColor) {
                    drawPiece(pieceCode, row, col, pieceColor);
                }
            }
        }
    }
}

// --- Event Listener Setup (Added for functionality, needed for completeness) ---

function handleCanvasClick(event) {
    const rect = canvas.getBoundingClientRect();
    const clientX = event.clientX - rect.left;
    const clientY = event.clientY - rect.top;

    const col = Math.floor(clientX / SQUARE_DIMENSION);
    const row = Math.floor(clientY / SQUARE_DIMENSION);

    if (row < 0 || row > 7 || col < 0 || col > 7) {
        return; // Clicked outside the board area
    }

    console.log(`Clicked at Row: ${row}, Col: ${col}`);

    if (gameState.selectedSource) {
        // Attempting to make a move
        const moveAttempt = { row: row, col: col };
        if (gameState.possibleMoves.some(move => move.row === row && move.col === col)) {
            // A valid move destination was clicked
            makeMove(gameState.selectedSource.row, gameState.selectedSource.col, row, col);
            return;
        }
    }

    // If no move was attempted or the move was invalid, try to select a new piece
    const pieceCode = gameState.board[row][col];
    let pieceColor = getPieceColor(pieceCode, row, col);

    if (pieceCode && pieceColor && pieceColor === gameState.currentPlayerColor) {
        // Select the piece
        gameState.selectedSource = { row: row, col: col };
        // In a real game, you would calculate possibleMoves here based on pieceCode and location
        // For now, we just clear potential moves and show selection.
        gameState.possibleMoves = []; 
        console.log(`Piece selected at (${row}, ${col}). Calculating moves needed.`);
        // Placeholder: For testing purposes, let's pretend we found a few fake moves if we click a white piece.
        if (gameState.currentPlayerColor === 'white') {
             gameState.possibleMoves = [{row: 7, col: 1}, {row: 6, col: 1}];
        }
    } else {
        // Deselect if clicking an empty or opponent's square when nothing was selected
        gameState.selectedSource = null;
        gameState.possibleMoves = [];
    }

    renderBoard();
}

/**
 * Placeholder function for executing a move.
 * @param {number} startRow
 * @param {number} startCol
 * @param {number} endRow
 * @param {number} endCol
 */
function makeMove(startRow, startCol, endRow, endCol) {
    const piece = gameState.board[startRow][startCol];

    // 1. Move the piece
    gameState.board[endRow][endCol] = piece;
    gameState.board[startRow][startCol] = null;

    // 2. Update selection/moves visual state
    gameState.selectedSource = null;
    gameState.possibleMoves = [];

    // 3. Switch turn (very basic switch)
    if (gameState.currentPlayerColor === 'white') {
        gameState.currentPlayerColor = 'black';
        gameState.turn = 'human'; // Human plays Black next
    } else {
        gameState.currentPlayerColor = 'white';
        gameState.turn = 'human'; // Human plays White next
    }

    console.log(`Moved ${piece} from (${startRow}, ${startCol}) to (${endRow}, ${endCol}). Turn switched to ${gameState.currentPlayerColor}.`);

    renderBoard();
}


// --- Initialization Hook ---
// The script executes this immediately, setting up the board structure.
initializeGame();
canvas.addEventListener('click', handleCanvasClick);
